// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::mod11::{self, SeloError};

/// Compute both coupled CNH check digits over the 9-digit base.
fn check_digits(base: &str) -> (i32, i32) {
    let bytes = base.as_bytes();
    let dsc;
    let dv1;
    let mut total = 0;
    for i in 0..9 {
        total += ((bytes[i] - b'0') as i32) * (9 - i as i32);
    }
    let mut r = total % 11;
    if r >= 10 {
        dv1 = 0;
        dsc = 2;
    } else {
        dv1 = r;
        dsc = 0;
    }
    total = 0;
    for i in 0..9 {
        total += ((bytes[i] - b'0') as i32) * (1 + i as i32);
    }
    r = (total % 11) - dsc;
    if r < 0 {
        r += 11;
    }
    let dv2 = if r >= 10 { 0 } else { r };
    (dv1, dv2)
}

/// Report whether value is a valid 11-digit CNH.
pub fn validate_cnh(value: &str) -> bool {
    let d = mod11::only_digits(value);
    if d.len() != 11 {
        return false;
    }
    if mod11::all_equal(&d) {
        return false;
    }
    let (dv1, dv2) = check_digits(&d[0..9]);
    let bytes = d.as_bytes();
    dv1 == (bytes[9] - b'0') as i32 && dv2 == (bytes[10] - b'0') as i32
}

/// Return the cleaned 11-digit CNH (no separator mask).
pub fn format_cnh(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() != 11 {
        return Err(SeloError::InvalidLength);
    }
    Ok(d)
}

/// Return a random, valid 11-digit CNH (unformatted).
pub fn generate_cnh() -> String {
    loop {
        let mut base = String::with_capacity(9);
        for _ in 0..9 {
            base.push_str(&mod11::rand_int(9).to_string());
        }
        let (dv1, dv2) = check_digits(&base);
        let out = format!("{}{}{}", base, dv1, dv2);
        if !mod11::all_equal(&out) {
            return out;
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/cnh.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_cnh(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_cnh(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_cnh(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_cnh();
            assert!(validate_cnh(&v), "generate produced invalid: {}", v);
        }
    }
}
